package kotlinx.coroutines

import kotlin.test.*
import kotlin.time.*
import kotlin.time.Duration.Companion.milliseconds
import kotlin.time.Duration.Companion.microseconds
import kotlin.time.Duration.Companion.nanoseconds
import kotlinx.coroutines.testing.*

/**
 * Tests that verify the fix for the issue where delay(Duration) improperly coerces
 * nanoseconds and microseconds, causing delays to be shorter than expected.
 */
class DelayDurationRoundUpTest : TestBase() {

    /**
     * Test that verifies delays with sub-millisecond components are not shorter than requested.
     * This is a simplified version of the reproducer from the issue.
     */
    @Test
    fun testDelayWithSubMillisecondComponentsIsNotShorter() = runTest {
        // Test various durations with sub-millisecond components
        val testCases = listOf(
            998.milliseconds + 902.microseconds,
            998.milliseconds + 759.microseconds + 90.nanoseconds,
            1.milliseconds + 500.microseconds,
            100.microseconds,
            999.nanoseconds,
            1.nanoseconds
        )

        for (expectedDuration in testCases) {
            val actualDuration = measureTime {
                delay(expectedDuration)
            }
            // The actual delay should be at least as long as expected
            // (allowing for some timing variation)
            assertTrue(
                actualDuration >= expectedDuration - 100.microseconds,
                "Expected delay of at least $expectedDuration, but got $actualDuration"
            )
        }
    }

    /**
     * Test that toDelayMillis() correctly rounds up sub-millisecond components.
     */
    @Test
    fun testToDelayMillisRoundsUp() {
        // Test cases where sub-millisecond components should cause rounding up
        assertEquals(1L, (0.milliseconds + 1.nanoseconds).toDelayMillis())
        assertEquals(1L, (0.milliseconds + 500.microseconds).toDelayMillis())
        assertEquals(1L, (0.milliseconds + 999.microseconds + 999.nanoseconds).toDelayMillis())
        assertEquals(999L, (998.milliseconds + 1.nanoseconds).toDelayMillis())
        assertEquals(999L, (998.milliseconds + 500.microseconds).toDelayMillis())
        assertEquals(999L, (998.milliseconds + 902.microseconds + 752.nanoseconds).toDelayMillis())

        // Test cases where there are no sub-millisecond components (no rounding needed)
        assertEquals(0L, (0.milliseconds).toDelayMillis())
        assertEquals(1L, (1.milliseconds).toDelayMillis())
        assertEquals(100L, (100.milliseconds).toDelayMillis())
        assertEquals(998L, (998.milliseconds).toDelayMillis())

        // Test negative and zero durations
        assertEquals(0L, (-1.milliseconds).toDelayMillis())
        assertEquals(0L, (Duration.ZERO).toDelayMillis())
    }

    /**
     * Test that delays with exact millisecond values work as before.
     */
    @Test
    fun testDelayWithExactMilliseconds() = runTest {
        val exactMilliseconds = listOf(1.milliseconds, 10.milliseconds, 100.milliseconds)

        for (duration in exactMilliseconds) {
            val actualDuration = measureTime {
                delay(duration)
            }
            // Should be at least the requested duration
            assertTrue(actualDuration >= duration - 100.microseconds)
        }
    }

    /**
     * Test the example from the issue report.
     */
    @Test
    fun testIssueReproducer() = runTest {
        // This is adapted from the issue report
        // Run a limited number of iterations to keep test fast
        repeat(10) {
            val expectedDuration = 998.milliseconds + 902.microseconds + 752.nanoseconds
            val actualDuration = measureTime { delay(expectedDuration) }
            val difference = actualDuration - expectedDuration

            // The actual duration should be at least as long as expected
            // With the fix, difference should be >= 0 (modulo timing precision)
            assertTrue(
                difference >= -100.microseconds,
                "Delay was too short: expected $expectedDuration, got $actualDuration, difference $difference"
            )
        }
    }

    /**
     * Test edge case: very small durations.
     */
    @Test
    fun testVerySmallDurations() = runTest {
        // These should all round up to 1 millisecond
        val smallDurations = listOf(
            1.nanoseconds,
            10.nanoseconds,
            100.nanoseconds,
            1.microseconds,
            10.microseconds,
            100.microseconds
        )

        for (duration in smallDurations) {
            assertEquals(1L, duration.toDelayMillis())
            // Actually running the delay
            val actualDuration = measureTime { delay(duration) }
            // Should delay for at least the requested time
            assertTrue(actualDuration >= duration - 100.microseconds)
        }
    }

    /**
     * Test that withTimeout also benefits from the fix.
     */
    @Test
    fun testWithTimeoutRoundsUp() = runTest {
        // This should time out after 2ms (rounded up from 1ms + 500us)
        val timeout = 1.milliseconds + 500.microseconds

        // Delay for exactly 1ms should succeed
        val result1 = withTimeoutOrNull(timeout) {
            delay(1.milliseconds)
            "success"
        }
        assertEquals("success", result1)
    }
}
"}

