package kotlinx.coroutines

import kotlin.test.*
import kotlin.time.*
import kotlin.time.Duration.Companion.milliseconds
import kotlin.time.Duration.Companion.microseconds
import kotlin.time.Duration.Companion.nanoseconds

/**
 * Tests that verify the fix for the issue where delay(Duration) improperly coerces
 * nanoseconds and microseconds, causing delays to be shorter than expected.
 */
class DelayDurationRoundUpTest : TestBase() {

    /**
     * Test that toDelayMillis() correctly rounds up sub-millisecond components.
     * This is the core fix - ensuring that any sub-millisecond component causes
     * the delay to round up to the next millisecond.
     */
    @Test
    fun testToDelayMillisRoundsUp() {
        // Test cases where sub-millisecond components should cause rounding up
        assertEquals(1L, (0.milliseconds + 1.nanoseconds).toDelayMillis())
        assertEquals(1L, (0.milliseconds + 500.microseconds).toDelayMillis())
        assertEquals(1L, (0.milliseconds + 999.microseconds + 999.nanoseconds).toDelayMillis())
        assertEquals(999L, (998.milliseconds + 1.nanoseconds).toDelayMillis())
        assertEquals(999L, (998.milliseconds + 500.microseconds).toDelayMillis())
        assertEquals(999L, (998.milliseconds + 902.microseconds + 752.nanoseconds).toDelayMillis())

        // Test cases where there are no sub-millisecond components (no rounding needed)
        assertEquals(1L, (1.milliseconds).toDelayMillis())
        assertEquals(100L, (100.milliseconds).toDelayMillis())
        assertEquals(998L, (998.milliseconds).toDelayMillis())

        // Test negative and zero durations
        assertEquals(0L, (-1.milliseconds).toDelayMillis())
        assertEquals(0L, (Duration.ZERO).toDelayMillis())
    }

    /**
     * Test edge case: very small durations.
     * All sub-millisecond durations should round up to 1 millisecond.
     */
    @Test
    fun testVerySmallDurations() {
        // These should all round up to 1 millisecond
        val smallDurations = listOf(
            1.nanoseconds,
            10.nanoseconds,
            100.nanoseconds,
            1.microseconds,
            10.microseconds,
            100.microseconds,
            999.microseconds
        )

        for (duration in smallDurations) {
            assertEquals(1L, duration.toDelayMillis(), 
                "Duration $duration should round up to 1 millisecond")
        }
    }

    /**
     * Test the specific example from the issue report.
     * The duration 998.75909ms should convert to 999ms, not 998ms.
     */
    @Test
    fun testIssueExample() {
        // This is the exact example from the issue
        val duration = 998.milliseconds + 759.microseconds + 90.nanoseconds
        val result = duration.toDelayMillis()

        // Should round up to 999ms, not truncate to 998ms
        assertEquals(999L, result, 
            "Duration 998.75909ms should round up to 999ms, not truncate to 998ms")
    }

    /**
     * Test that delays with exact millisecond values work as before.
     * These should not be affected by the fix.
     */
    @Test
    fun testExactMilliseconds() {
        assertEquals(1L, (1.milliseconds).toDelayMillis())
        assertEquals(10L, (10.milliseconds).toDelayMillis())
        assertEquals(100L, (100.milliseconds).toDelayMillis())
        assertEquals(1000L, (1000.milliseconds).toDelayMillis())
    }

    /**
     * Test that the fix preserves the original behavior for positive durations
     * less than 1 millisecond - they should round up to at least 1ms.
     */
    @Test
    fun testPositiveDurationsCoercedToAtLeastOne() {
        // Even tiny positive durations should result in at least 1ms
        assertTrue((1.nanoseconds).toDelayMillis() >= 1L)
        assertTrue((0.5.milliseconds).toDelayMillis() >= 1L)
    }

    /**
     * Test that withTimeout also benefits from the fix.
     * Timeouts with sub-millisecond components should round up.
     */
    @Test
    fun testWithTimeoutRoundsUp() = runTest {
        // This should time out after 2ms (rounded up from 1ms + 500us)
        val timeout = 1.milliseconds + 500.microseconds

        // The timeout should be 2ms due to rounding up
        assertEquals(2L, timeout.toDelayMillis())

        // Delay for exactly 1ms should succeed
        val result = withTimeoutOrNull(timeout) {
            delay(1.milliseconds)
            "success"
        }
        assertEquals("success", result)
    }

    /**
     * Test that delay() actually works correctly with durations that have
     * sub-millisecond components.
     */
    @Test
    fun testDelayWithSubMillisecondComponents() = runTest {
        // These delays should all complete without errors
        delay(1.nanoseconds)
        delay(500.microseconds)
        delay(998.milliseconds + 500.microseconds)

        // The test passing means the delays completed successfully
    }
}"}

